import React, { useMemo, useState } from 'react';

function DeeplyNestedMemo({ data }) {
  const memo = useMemo(() => JSON.stringify(data), [JSON.stringify(data)]);
  return <div>{memo}</div>;
}

export default DeeplyNestedMemo;

